import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { HTMLAttributes, ReactNode } from 'react';
import type { AllStatuses } from '../../types/status';
export type AssignLabelVariants = 'outline' | 'contained' | 'icon';
export interface LabelProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
    /** Тип метки (определяет цвет подложки и границы)*/
    type?: AllStatuses;
    /** "будет удалено" Назначение метки (определяет содержимое (текст / иконка / текст с иконкой)) */
    assign?: AssignLabelVariants;
    /** Назначение метки (определяет содержимое (текст / иконка / текст с иконкой))*/
    variant?: AssignLabelVariants;
    /** Текст метки, отображается только в метках с назначением (текст / текст с иконкой) */
    title?: ReactNode;
    /** Иконка метки, отображается только в метках с назначением (иконка) */
    iconName?: Icons;
    /** Пользовательский класс */
    className?: string;
}
